// filepath: c:\Users\ariel\OneDrive\Documentos\Repositorio_proyecto\proyectoRetaurant\frontend-admin\src\App.tsx
import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Layout from "./components/layout/Layout";
import MenuAdmin from "./components/admin/MenuAdmin";
import MesasAdmin from "./components/admin/MesasAdmin";
import UsuariosAdmin from "./components/admin/UsuariosAdmin";
import PedidosAdmin from "./components/admin/PedidosAdmin";

function App() {
  return (
    <BrowserRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<MenuAdmin />} />
          <Route path="/menu" element={<MenuAdmin />} />
          <Route path="/mesas" element={<MesasAdmin />} />
          <Route path="/usuarios" element={<UsuariosAdmin />} />
          <Route path="/pedidos" element={<PedidosAdmin />} />
          <Route
            path="*"
            element={
              <div className="p-8 text-center">
                <h1 className="text-2xl font-bold text-gray-800 mb-4">
                  Página no encontrada
                </h1>
                <p className="text-gray-600">La página que buscas no existe.</p>
              </div>
            }
          />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
}

export default App;
